import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  BarChart,
  Users,
  Package,
  Settings,
  LogOut,
  Search,
  Shirt,
  DollarSign,
  Truck,
  Clock,
  FileDown,
  Store,
  Layout,
  MapPin,
  Calendar,
  X,
  ChevronRight,
  CheckCircle,
  AlertCircle,
  Contact
} from 'lucide-react';
import Login from './Login';
import Reports from './Reports';
import SuperAdminPanel from './SuperAdminPanel';
import Customers from './Customers';
import Drivers from './Drivers';
import SettingsPage from './Settings';
import './App.css';
import { API_URL } from './config';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(() => {
    return !!(localStorage.getItem('gowash_token') && localStorage.getItem('gowash_user'));
  });

  const [currentUser, setCurrentUser] = useState(() => {
    const user = localStorage.getItem('gowash_user');
    return user ? JSON.parse(user) : null;
  });

  const [orders, setOrders] = useState([]);
  const [stats, setStats] = useState({ totalOrders: 0, revenue: 0, pending: 0, washing: 0 });

  const [activeTab, setActiveTab] = useState(() => {
    const user = localStorage.getItem('gowash_user');
    if (user) {
      const userData = JSON.parse(user);
      if (userData.role === 'superadmin') return 'Laundries';
    }
    return 'Overview';
  });

  const [filter, setFilter] = useState('All');

  const [newOrder, setNewOrder] = useState(null);
  const [selectedOrder, setSelectedOrder] = useState(null);
  // Create a simple notification beep sound using Web Audio API
  const audioRef = React.useRef(null);

  useEffect(() => {
    // Initialize audio with a notification sound
    const audio = new Audio();
    audio.src = 'data:audio/wav;base64,';
    audioRef.current = audio;

    // FIX: Unlock audio on first user interaction
    const unlockAudio = () => {
      if (audioRef.current) {
        audioRef.current.play().then(() => {
          audioRef.current.pause();
          audioRef.current.currentTime = 0;
        }).catch(e => console.log("Audio unlock failed", e));
      }
      document.removeEventListener('click', unlockAudio);
    };
    document.addEventListener('click', unlockAudio);

    return () => document.removeEventListener('click', unlockAudio);
  }, []);



  const playNotification = () => {
    try {
      if (audioRef.current) {
        audioRef.current.loop = true;
        audioRef.current.volume = 0.5;
        audioRef.current.play().catch(e => console.log("Audio play failed (interaction needed):", e));
      }
    } catch (e) {
      console.error(e);
    }
  };

  const stopNotification = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      audioRef.current.loop = false;
    }
  };

  const fetchOrders = async () => {
    try {
      const laundryId = currentUser?.laundry_id;
      const [ordersRes, statsRes] = await Promise.all([
        axios.get(`${API_URL}/orders`, { params: { role: currentUser?.role, laundryId } }),
        axios.get(`${API_URL}/stats/orders`, { params: { laundryId } })
      ]);

      if (ordersRes.data) {
        const fetchedOrders = ordersRes.data;
        setOrders(fetchedOrders);

        // Check for new pending orders (for both admin and superadmin)
        const pending = fetchedOrders.filter(o => o.status === 'Pending');
        if (pending.length > 0) {
          // Sort to get the latest by ID
          const latest = [...pending].sort((a, b) => b.id - a.id)[0];

          const lastSeen = sessionStorage.getItem('last_seen_order');
          if (!lastSeen || parseInt(lastSeen) < latest.id) {
            setNewOrder(latest);
            sessionStorage.setItem('last_seen_order', latest.id);
            playNotification();
          }
        }
      }

      if (statsRes.data) {
        const s = statsRes.data;
        setStats({
          totalOrders: s.totalOrders,
          revenue: s.totalRevenue,
          pending: s.pendingOrders,
          washing: s.activeOrders
        });
      }
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    let interval;
    if (isAuthenticated) {

      setTimeout(fetchOrders, 0); // Initial fetch
      interval = setInterval(fetchOrders, 5000); // Poll every 5s
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isAuthenticated, currentUser?.role]);

  const handleLogin = (user) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.role === 'superadmin') {
      setActiveTab('Laundries');
    } else {
      setActiveTab('Overview');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('gowash_token');
    localStorage.removeItem('gowash_user');
    setIsAuthenticated(false);
    setCurrentUser(null);
    setNewOrder(null);
    stopNotification(); // Stop any playing notification sound
    sessionStorage.removeItem('last_seen_order'); // Clear last seen order
  };

  const updateStatus = async (id, newStatus) => {
    try {
      if (newOrder && newOrder.id === id) {
        setNewOrder(null);
        stopNotification();
      }
      await axios.patch(`${API_URL}/orders/${id}/status`, { status: newStatus });
      fetchOrders();
    } catch (error) {
      console.error(error);
      alert("Failed to update status");
    }
  };

  const filteredOrders = filter === 'All' ? orders : orders.filter(o => o.status === filter);

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="app-container">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-header">
          <div className="logo">
            <Shirt size={32} />
            <div>
              <h1>GoWash</h1>
              <p>Admin Portal</p>
            </div>
          </div>
        </div>

        <nav className="sidebar-nav">
          {currentUser?.role === 'superadmin' ? (
            <>
               <SidebarItem icon={<Store size={20} />} label="Laundries" active={activeTab === 'Laundries'} onClick={() => setActiveTab('Laundries')} />
               <SidebarItem icon={<Users size={20} />} label="Customers" active={activeTab === 'Customers'} onClick={() => setActiveTab('Customers')} />
               <SidebarItem icon={<Truck size={20} />} label="Drivers" active={activeTab === 'Drivers'} onClick={() => setActiveTab('Drivers')} />
               <SidebarItem icon={<FileDown size={20} />} label="Global Reports" active={activeTab === 'Reports'} onClick={() => setActiveTab('Reports')} />
              <SidebarItem icon={<Settings size={20} />} label="System Settings" active={activeTab === 'Settings'} onClick={() => setActiveTab('Settings')} />
            </>
          ) : (
            <>
              <SidebarItem icon={<BarChart size={20} />} label="Overview" active={activeTab === 'Overview'} onClick={() => setActiveTab('Overview')} />
              <SidebarItem icon={<Package size={20} />} label="Orders" active={activeTab === 'Orders'} onClick={() => setActiveTab('Orders')} />
              <SidebarItem icon={<FileDown size={20} />} label="Reports" active={activeTab === 'Reports'} onClick={() => setActiveTab('Reports')} />
              <SidebarItem icon={<Settings size={20} />} label="Settings" active={activeTab === 'Settings'} onClick={() => setActiveTab('Settings')} />
            </>
          )}
        </nav>

        <div className="sidebar-footer">
          <button className="logout-btn" onClick={handleLogout}>
            <LogOut size={20} />
            <span>Logout</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {/* Header */}
        <header className="header">
          <h2>{activeTab}</h2>
          <div className="header-actions">
            <div className="search-box">
              <Search size={18} />
              <input type="text" placeholder="Search orders..." />
            </div>
            <div className="user-info">
              <span className="user-name">{currentUser?.name}</span>
              <div className="user-avatar">{currentUser?.name?.charAt(0) || 'A'}</div>
            </div>
            <button className="mobile-logout-btn" onClick={handleLogout} title="Logout">
              <LogOut size={20} />
            </button>
          </div>
        </header>

        <div className="content-area">
          {activeTab === 'Laundries' && <SuperAdminPanel />}

          {activeTab === 'Overview' && (
            <>
              <div className="stats-grid">
                <StatCard title="Total Revenue" value={`LKR ${stats.revenue.toLocaleString()}`} icon={<DollarSign />} color="green" />
                <StatCard title="Total Orders" value={stats.totalOrders} icon={<Package />} color="blue" />
                <StatCard title="Pending Pickup" value={stats.pending} icon={<Truck />} color="yellow" />
                <StatCard title="In Processing" value={stats.washing} icon={<Clock />} color="purple" />
              </div>

              <div className="card">
                <div className="card-header">
                  <h3>Recent Orders</h3>
                  <button className="link-btn" onClick={() => setActiveTab('Orders')}>View All</button>
                </div>
                <OrdersTable orders={orders.slice(0, 5)} updateStatus={updateStatus} onView={setSelectedOrder} />
              </div>
            </>
          )}

          {activeTab === 'Orders' && (
            <div className="card">
              <div className="card-header filter-header">
                <div className="filter-buttons">
                  {['All', 'Pending', 'Confirmed', 'Pickup', 'Washing', 'Drying', 'Ready', 'Delivered', 'Cancelled'].map(status => (
                    <button
                      key={status}
                      onClick={() => setFilter(status)}
                      className={`filter-btn ${filter === status ? 'active' : ''}`}
                    >
                      {status}
                    </button>
                  ))}
                </div>
              </div>
              <OrdersTable orders={filteredOrders} updateStatus={updateStatus} onView={setSelectedOrder} />
            </div>
          )}

          {activeTab === 'Customers' && (
            <Customers currentUser={currentUser} />
          )}

          {activeTab === 'Drivers' && (
            <Drivers currentUser={currentUser} />
          )}

          {activeTab === 'Reports' && (
            <Reports currentUser={currentUser} />
          )}

          {activeTab === 'Settings' && (
            <SettingsPage currentUser={currentUser} />
          )}
        </div>
      </main>

      {/* New Order Notification Modal - Only for admin users */}
      {newOrder && currentUser?.role === 'admin' && (
        <div className="modal-overlay">
          <div className="modal-content professional-modal">
            <div className="modal-header-professional">
              <div className="header-top">
                <div className="status-badge-new">
                  <AlertCircle size={14} /> NEW ORDER
                </div>
                <button
                  className="close-modal-btn-pro"
                  onClick={() => {
                    setNewOrder(null);
                    stopNotification();
                  }}
                >
                  <X size={20} />
                </button>
              </div>
              <div className="order-number-large">
                <span>Order #</span>{newOrder.id}
              </div>
              <p className="order-time-ago">Just now</p>
            </div>

            <div className="modal-body-pro">
              <div className="customer-section">
                <div className="customer-avatar-pro">
                  {newOrder.customer_name?.charAt(0) || 'C'}
                </div>
                <div className="customer-info">
                  <h3>{newOrder.customer_name}</h3>
                  <p>Customer</p>
                </div>
                <div className="total-amount-badge">
                  LkR {newOrder.total_price}
                </div>
              </div>

              <div className="order-details-grid">
                <div className="detail-item-pro">
                  <div className="icon-box blue">
                    <Shirt size={18} />
                  </div>
                  <div className="detail-text">
                    <label>Service</label>
                    <p>{newOrder.serviceName} ΓÇó {newOrder.items} Items</p>
                  </div>
                </div>

                <div className="detail-item-pro">
                  <div className="icon-box purple">
                    <Clock size={18} />
                  </div>
                  <div className="detail-text">
                    <label>Pickup Time</label>
                    <p>{newOrder.pickup_date}</p>
                    <p className="sub-text">{newOrder.pickup_time}</p>
                  </div>
                </div>

                <div className="detail-item-pro full-width">
                  <div className="icon-box green">
                    <MapPin size={18} />
                  </div>
                  <div className="detail-text">
                    <label>Delivery Address</label>
                    <p>{newOrder.address || 'No location provided'}</p>
                  </div>
                </div>
              </div>

              <div className="modal-actions-pro">
                <button
                  className="btn-pro btn-reject-pro"
                  onClick={() => {
                    updateStatus(newOrder.id, 'Cancelled');
                    setNewOrder(null);
                    stopNotification();
                  }}
                >
                  Decline Order
                </button>
                <button
                  className="btn-pro btn-accept-pro"
                  onClick={() => {
                    updateStatus(newOrder.id, 'Confirmed');
                    setNewOrder(null);
                    stopNotification();
                  }}
                >
                  Accept Order <ChevronRight size={16} />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Order Details Modal */}
      {selectedOrder && (
        <div className="modal-overlay" onClick={() => setSelectedOrder(null)}>
          <div className="modal-content professional-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header-professional" style={{ background: '#4c669f' }}>
              <div className="header-top">
                <div className="status-badge-new" style={{ background: 'rgba(255,255,255,0.2)', color: 'white', borderColor: 'rgba(255,255,255,0.3)' }}>
                  ORDER DETAILS
                </div>
                <button className="close-modal-btn-pro" onClick={() => setSelectedOrder(null)}>
                  <X size={20} />
                </button>
              </div>
              <div className="order-number-large">
                <span>Order #</span>{selectedOrder.id}
              </div>
              <p className="order-time-ago">{new Date(selectedOrder.created_at).toLocaleString()}</p>
            </div>

            <div className="modal-body-pro">
              <div className="customer-section">
                <div className="customer-avatar-pro" style={{ background: 'var(--primary)' }}>
                  {selectedOrder.customer_name?.charAt(0) || 'C'}
                </div>
                <div className="customer-info">
                  <h3>{selectedOrder.customer_name}</h3>
                  <p>{selectedOrder.laundryName} branch</p>
                </div>
                <div className="total-amount-badge">
                  LKR {selectedOrder.total_price}
                </div>
              </div>

              <div className="order-items-detail card">
                <div className="card-header" style={{ padding: '12px 20px' }}>
                  <h4 style={{ margin: 0, fontSize: '14px' }}>Itemized Breakdown</h4>
                </div>
                <div className="items-list-pro" style={{ padding: '10px' }}>
                  {selectedOrder.itemsList && selectedOrder.itemsList.length > 0 &&
                    selectedOrder.itemsList.map((item, idx) => (
                      <div key={idx} className="item-row-pro" style={{ display: 'flex', justifyContent: 'space-between', padding: '10px', borderBottom: idx === selectedOrder.itemsList.length - 1 ? 'none' : '1px solid #f1f5f9' }}>
                        <div>
                          <p style={{ margin: 0, fontWeight: '600', fontSize: '14px' }}>{item.item_name} <span style={{ color: '#64748b', fontWeight: '400' }}>x {item.quantity}</span></p>
                          <p style={{ margin: 0, fontSize: '11px', color: '#94a3b8' }}>LKR {item.price_per_unit} per unit</p>
                        </div>
                        <p style={{ margin: 0, fontWeight: '700', color: 'var(--primary)' }}>LKR {item.total_price}</p>
                      </div>
                    ))
                  }
                  {(!selectedOrder.itemsList || selectedOrder.itemsList.length === 0) && (
                    <p style={{ textAlign: 'center', padding: '20px', color: '#94a3b8' }}>No item details available</p>
                  )}
                  {selectedOrder.delivery_fee > 0 && (
                    <div className="item-row-pro" style={{ display: 'flex', justifyContent: 'space-between', padding: '10px', background: '#f8fafc', borderTop: '1px dashed #cbd5e1' }}>
                      <p style={{ margin: 0, fontWeight: '600', fontSize: '14px', color: '#64748b' }}>Delivery Charge</p>
                      <p style={{ margin: 0, fontWeight: '700', color: 'var(--primary)' }}>LKR {selectedOrder.delivery_fee}</p>
                    </div>
                  )}
                </div>
              </div>

              <div className="order-details-grid">
                <div className="detail-item-pro">
                  <div className="icon-box blue"><Shirt size={18} /></div>
                  <div className="detail-text">
                    <label>Master Service</label>
                    <p>{selectedOrder.serviceName}</p>
                  </div>
                </div>
                <div className="detail-item-pro">
                  <div className="icon-box purple"><Clock size={18} /></div>
                  <div className="detail-text">
                    <label>Pickup Date</label>
                    <p>{selectedOrder.pickup_date}</p>
                    <p className="sub-text">{selectedOrder.pickup_time}</p>
                  </div>
                </div>
                <div className="detail-item-pro full-width">
                  <div className="icon-box green"><MapPin size={18} /></div>
                  <div className="detail-text">
                    <label>Delivery Address</label>
                    <p>{selectedOrder.address}</p>
                  </div>
                </div>
                {selectedOrder.notes && (
                  <div className="detail-item-pro full-width">
                    <div className="icon-box yellow" style={{ background: '#fef3c7', color: '#f59e0b' }}><AlertCircle size={18} /></div>
                    <div className="detail-text">
                      <label>Order Notes</label>
                      <p style={{ fontSize: '13px', fontWeight: '400' }}>{selectedOrder.notes}</p>
                    </div>
                  </div>
                )}
              </div>
            </div>
            <div className="modal-footer" style={{ padding: '20px 28px' }}>
              <button className="save-btn" style={{ width: '100%' }} onClick={() => setSelectedOrder(null)}>Done</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const SidebarItem = ({ icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`sidebar-item ${active ? 'active' : ''}`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

const StatCard = ({ title, value, icon, color }) => (
  <div className="stat-card">
    <div className="stat-info">
      <p className="stat-title">{title}</p>
      <h3 className="stat-value">{value}</h3>
    </div>
    <div className={`stat-icon ${color}`}>{icon}</div>
  </div>
);

const OrdersTable = ({ orders, updateStatus, onView }) => {
  const getStatusClass = (status) => {
    switch (status) {
      case 'Pending': return 'status-pending';
      case 'Confirmed': return 'status-confirmed';
      case 'Pickup': return 'status-pickup';
      case 'Washing': return 'status-washing';
      case 'Drying': return 'status-drying';
      case 'Ready': return 'status-ready';
      case 'Delivered': return 'status-delivered';
      case 'Cancelled': return 'status-cancelled';
      default: return 'status-default';
    }
  };

  return (
    <div className="table-container">
      <table className="orders-table">
        <thead>
          <tr>
            <th>Order ID</th>
            <th>Customer</th>
            <th>Service</th>
            <th>Items</th>
            <th>Total</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {orders.map(order => (
            <tr key={order.id}>
              <td className="order-id">#{order.id}</td>
              <td>{order.customer_name || `User ${order.user_id}`}</td>
              <td>
                <span className="service-badge">
                  {order.serviceName}
                </span>
              </td>
              <td>{order.items}</td>
              <td className="price">LKR {order.total_price}</td>
              <td>
                <span className={`status-badge ${getStatusClass(order.status)}`}>
                  {order.status}
                </span>
              </td>
              <td>
                <select
                  className="status-select"
                  value={order.status}
                  onChange={(e) => updateStatus(order.id, e.target.value)}
                >
                  <option value="Pending">Pending</option>
                  <option value="Confirmed">Confirmed</option>
                  <option value="Pickup">Pickup</option>
                  <option value="Washing">Washing</option>
                  <option value="Drying">Drying</option>
                  <option value="Ready">Ready</option>
                  <option value="Delivered">Delivered</option>
                  <option value="Cancelled">Cancelled</option>
                </select>
                <button
                  className="status-select"
                  style={{ marginLeft: '8px', padding: '8px', color: 'var(--primary)' }}
                  onClick={() => onView(order)}
                  title="View Details"
                >
                  <Search size={16} />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Mail, Phone, Calendar, User, Search, RefreshCw, Loader2, ArrowLeft, ShoppingBag, DollarSign, Clock } from 'lucide-react';
import './Customers.css';
import { API_URL } from './config';

const Customers = ({ currentUser }) => {
    const [customers, setCustomers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [activeRole, setActiveRole] = useState('customer'); // Default to customer

    // Detailed View State
    const [selectedCustomer, setSelectedCustomer] = useState(null);
    const [customerOrders, setCustomerOrders] = useState([]);
    const [ordersLoading, setOrdersLoading] = useState(false);

     
    useEffect(() => {
        if (!selectedCustomer) {
            fetchCustomers();
        }
    }, [currentUser, selectedCustomer, activeRole]);

    const fetchCustomers = async () => {
        try {
            setLoading(true);
            const params = { role: activeRole };
            if (currentUser?.laundry_id) {
                params.laundryId = currentUser.laundry_id;
            }
            const res = await axios.get(`${API_URL}/users`, { params });
            setCustomers(res.data);
        } catch (error) {
            console.error('Error fetching customers:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleViewProfile = async (customer) => {
        setSelectedCustomer(customer);
        setOrdersLoading(true);
        try {
            const params = { userId: customer.id };
            // Ensure we filter by laundry ONLY if the current user is a Laundry Admin
            // If SuperAdmin, they see ALL orders for that user
            if (currentUser?.laundry_id) {
                params.laundryId = currentUser.laundry_id;
            }

            const res = await axios.get(`${API_URL}/orders`, { params });
            setCustomerOrders(res.data);
        } catch (error) {
            console.error('Error fetching customer orders:', error);
        } finally {
            setOrdersLoading(false);
        }
    };

    const handleBack = () => {
        setSelectedCustomer(null);
        setCustomerOrders([]);
    };

    const filteredCustomers = customers.filter(c =>
        c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        c.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (c.phone && c.phone.includes(searchQuery))
    );

    // Calculate customer stats
    const totalSpent = customerOrders.reduce((sum, order) => sum + parseFloat(order.total_price || 0), 0);
    const completedOrdersCount = customerOrders.filter(o => o.status === 'Delivered').length;

    if (selectedCustomer) {
        return (
            <div className="customers-container">
                <div className="profile-header">
                    <button className="back-btn" onClick={handleBack}>
                        <ArrowLeft size={18} /> Back to {activeRole === 'customer' ? 'Customers' : 'Agents'}
                    </button>
                </div>

                <div className="profile-content">
                    {/* Customer Info Card */}
                    <div className="profile-info-card">
                        <div className={`profile-avatar-large ${activeRole === 'agent' ? 'agent-avatar' : ''}`}>
                            {selectedCustomer.name.charAt(0).toUpperCase()}
                        </div>
                        <h2 className="profile-name">{selectedCustomer.name}</h2>
                        <div className="profile-details">
                            <div className="detail-item">
                                <Mail size={16} /> <span>{selectedCustomer.email}</span>
                            </div>
                            {selectedCustomer.phone && (
                                <div className="detail-item">
                                    <Phone size={16} /> <span>{selectedCustomer.phone}</span>
                                </div>
                            )}
                            <div className="detail-item">
                                <Calendar size={16} />
                                <span>Joined {new Date(selectedCustomer.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    </div>

                    {/* Stats & Orders */}
                    <div className="profile-main">
                        <div className="stats-row">
                            <div className="stat-box blue">
                                <div className="stat-icon-bg">
                                    <ShoppingBag size={24} />
                                </div>
                                <div className="stat-text">
                                    <label>Total Orders</label>
                                    <h3>{customerOrders.length}</h3>
                                </div>
                            </div>
                            <div className="stat-box green">
                                <div className="stat-icon-bg">
                                    <DollarSign size={24} />
                                </div>
                                <div className="stat-text">
                                    <label>Total {activeRole === 'customer' ? 'Spent' : 'Revenue'}</label>
                                    <h3>LKR {totalSpent.toFixed(2)}</h3>
                                </div>
                            </div>
                            <div className="stat-box purple">
                                <div className="stat-icon-bg">
                                    <Clock size={24} />
                                </div>
                                <div className="stat-text">
                                    <label>Completed</label>
                                    <h3>{completedOrdersCount}</h3>
                                </div>
                            </div>
                        </div>

                        <div className="orders-section">
                            <h3>Order History</h3>
                            {ordersLoading ? (
                                <div className="loader-container">
                                    <Loader2 className="animate-spin" size={32} color="#4facfe" />
                                </div>
                            ) : customerOrders.length === 0 ? (
                                <div className="empty-state-small">
                                    <p>No orders found for this {activeRole}.</p>
                                </div>
                            ) : (
                                <div className="table-container">
                                    <table className="orders-table">
                                        <thead>
                                            <tr>
                                                <th>Order ID</th>
                                                <th>Service</th>
                                                <th>Date</th>
                                                <th>Total</th>
                                                <th>Status</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {customerOrders.map(order => (
                                                <tr key={order.id}>
                                                    <td className="order-id">#{order.id}</td>
                                                    <td>{order.serviceName}</td>
                                                    <td>{new Date(order.created_at).toLocaleDateString()}</td>
                                                    <td className="price">LKR {order.total_price}</td>
                                                    <td>
                                                        <span className={`status-badge status-${order.status.toLowerCase()}`}>
                                                            {order.status}
                                                        </span>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="customers-container">
            <div className="page-header">
                <div>
                    <h2>{currentUser?.role === 'superadmin' ? 'User Management' : 'My Customers'}</h2>
                    <p className="subtitle">
                        {currentUser?.role === 'superadmin'
                            ? 'Manage customers and agents in the system'
                            : 'Manage and view your customer database'}
                    </p>
                </div>
                <div className="header-actions">
                    <div className="search-box">
                        <Search size={18} />
                        <input
                            type="text"
                            placeholder={`Search ${activeRole}s...`}
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            {currentUser?.role === 'superadmin' && (
                <div className="filter-tabs">
                    <button 
                        className={`tab-btn ${activeRole === 'customer' ? 'active' : ''}`}
                        onClick={() => setActiveRole('customer')}
                    >
                        Customers
                    </button>
                    <button 
                        className={`tab-btn ${activeRole === 'agent' ? 'active' : ''}`}
                        onClick={() => setActiveRole('agent')}
                    >
                        Agents
                    </button>
                </div>
            )}

            {loading ? (
                <div className="loader-container">
                    <Loader2 className="animate-spin" size={48} color="#4facfe" />
                </div>
            ) : (
                <div className="table-card">
                    {filteredCustomers.length === 0 ? (
                        <div className="empty-state">
                            <User size={64} />
                            <h3>No {activeRole}s found</h3>
                            <p>Once {activeRole}s are registered, they will appear here.</p>
                        </div>
                    ) : (
                        <table className="customers-table">
                            <thead>
                                <tr>
                                    <th>{activeRole === 'customer' ? 'Customer' : 'Agent'} Name</th>
                                    <th>Contact Info</th>
                                    <th>Role</th>
                                    <th>Joined Date</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredCustomers.map(customer => (
                                    <tr key={customer.id}>
                                        <td>
                                            <div className="customer-cell">
                                                <div className={`avatar-circle ${activeRole === 'agent' ? 'agent-avatar' : ''}`}>
                                                    {customer.name.charAt(0).toUpperCase()}
                                                </div>
                                                <span className="customer-name">{customer.name}</span>
                                            </div>
                                        </td>
                                        <td>
                                            <div className="contact-info">
                                                <div className="contact-row">
                                                    <Mail size={14} /> <span>{customer.email}</span>
                                                </div>
                                                {customer.phone && (
                                                    <div className="contact-row">
                                                        <Phone size={14} /> <span>{customer.phone}</span>
                                                    </div>
                                                )}
                                            </div>
                                        </td>
                                        <td>
                                            <span className={`role-badge ${customer.role}`}>
                                                {customer.role.toUpperCase()}
                                            </span>
                                        </td>
                                        <td>
                                            <div className="date-cell">
                                                <Calendar size={14} />
                                                <span>{new Date(customer.createdAt).toLocaleDateString()}</span>
                                            </div>
                                        </td>
                                        <td>
                                            <button className="view-btn" onClick={() => handleViewProfile(customer)}>
                                                View Profile
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            )}
        </div>
    );
};

export default Customers;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
    Users, Search, Shield, Eye, CheckCircle, XCircle
} from 'lucide-react';
import './Drivers.css';
import { API_URL } from './config';

function Drivers() {
    const [drivers, setDrivers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedDriver, setSelectedDriver] = useState(null);
    const [filter, setFilter] = useState('All');

    const fetchDrivers = async () => {
        try {
            const res = await axios.get(`${API_URL}/admin/drivers`);
            setDrivers(res.data);
            setLoading(false);
        } catch (error) {
            console.error("Error fetching drivers:", error);
            setLoading(false);
        }
    };

     
    useEffect(() => {
         
        setTimeout(fetchDrivers, 0);
    }, []);

    const updateDriverStatus = async (driverId, newStatus) => {
        try {
            await axios.patch(`${API_URL}/drivers/${driverId}/status`, { status: newStatus });
            fetchDrivers();
            if (selectedDriver && selectedDriver.id === driverId) {
                setSelectedDriver({ ...selectedDriver, status: newStatus });
            }
        } catch (error) {
            console.error(error);
            alert("Failed to update status");
        }
    };

    const filteredDrivers = filter === 'All'
        ? drivers
        : drivers.filter(d => d.status === filter);

    const getStatusColor = (status) => {
        switch (status) {
            case 'active': case 'approved': return 'green';
            case 'pending': case 'pending_approval': return 'yellow';
            case 'rejected': case 'suspended': return 'red';
            default: return 'gray';
        }
    };

    return (
        <div className="drivers-container">
            <div className="section-header">
                <div className="header-title">
                    <Users size={24} />
                    <h2>Driver Management</h2>
                </div>
                <div className="header-actions">
                    <div className="search-box">
                        <Search size={18} />
                        <input type="text" placeholder="Search drivers..." />
                    </div>
                </div>
            </div>

            <div className="drivers-stats">
                <div className="stat-card">
                    <h3>Total Drivers</h3>
                    <p>{drivers.length}</p>
                </div>
                <div className="stat-card">
                    <h3>Active</h3>
                    <p>{drivers.filter(d => d.status === 'active' || d.status === 'approved').length}</p>
                </div>
                <div className="stat-card pending">
                    <h3>Pending Approval</h3>
                    <p>{drivers.filter(d => d.status === 'pending_approval').length}</p>
                </div>
            </div>

            <div className="card">
                <div className="card-header filter-header">
                    <h3>Driver List</h3>
                    <div className="filter-buttons">
                        {['All', 'active', 'pending_approval', 'suspended'].map(status => (
                            <button
                                key={status}
                                onClick={() => setFilter(status)}
                                className={`filter-btn ${filter === status ? 'active' : ''}`}
                            >
                                {status === 'pending_approval' ? 'Pending' : status.charAt(0).toUpperCase() + status.slice(1)}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="table-container">
                    <table className="drivers-table">
                        <thead>
                            <tr>
                                <th>ID</th>
                                <th>Driver</th>
                                <th>Contact</th>
                                <th>Vehicle</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredDrivers.map(driver => (
                                <tr key={driver.id}>
                                    <td>#{driver.id}</td>
                                    <td>
                                        <div className="driver-cell">
                                            <div className="driver-avatar">
                                                {driver.profile_image_url ? (
                                                    <img src={driver.profile_image_url} alt="Profile" />
                                                ) : (
                                                    <span>{driver.name?.charAt(0)}</span>
                                                )}
                                            </div>
                                            <div>
                                                <p className="driver-name">{driver.name}</p>
                                                <p className="driver-email">{driver.email}</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td>
                                        <p>{driver.phone}</p>
                                        <p className="sub-text">NIC: {driver.nic_number}</p>
                                    </td>
                                    <td>
                                        <p className="vehicle-plate">{driver.vehicle_number}</p>
                                        <p className="sub-text">{driver.vehicle_type}</p>
                                    </td>
                                    <td>
                                        <span className={`status-badge ${getStatusColor(driver.status)}`}>
                                            {driver.status === 'pending_approval' ? 'Pending' : driver.status}
                                        </span>
                                    </td>
                                    <td>
                                        <button
                                            className="view-btn"
                                            onClick={() => setSelectedDriver(driver)}
                                        >
                                            <Eye size={18} /> View
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Driver Details Modal */}
            {selectedDriver && (
                <div className="modal-overlay" onClick={() => setSelectedDriver(null)}>
                    <div className="modal-content driver-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h3>Driver Details</h3>
                            <button className="close-btn" onClick={() => setSelectedDriver(null)}>├ù</button>
                        </div>

                        <div className="modal-body driver-details-body">
                            <div className="driver-profile-header">
                                <div className="large-avatar">
                                    {selectedDriver.profile_image_url ? (
                                        <img src={selectedDriver.profile_image_url} alt="Profile" />
                                    ) : (
                                        <span>{selectedDriver.name?.charAt(0)}</span>
                                    )}
                                </div>
                                <div className="driver-main-info">
                                    <h2>{selectedDriver.name}</h2>
                                    <p>{selectedDriver.email}</p>
                                    <p>{selectedDriver.phone}</p>
                                    <div className="status-actions">
                                        <span className={`status-badge ${getStatusColor(selectedDriver.status)}`}>
                                            {selectedDriver.status}
                                        </span>
                                        {selectedDriver.status === 'pending_approval' && (
                                            <div className="approval-buttons">
                                                <button
                                                    className="approve-btn"
                                                    onClick={() => updateDriverStatus(selectedDriver.id, 'active')}
                                                >
                                                    <CheckCircle size={16} /> Approve
                                                </button>
                                                <button
                                                    className="reject-btn"
                                                    onClick={() => updateDriverStatus(selectedDriver.id, 'rejected')}
                                                >
                                                    <XCircle size={16} /> Reject
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>

                            <div className="details-grid">
                                <div className="detail-section">
                                    <h4>Information</h4>
                                    <p><strong>NIC:</strong> {selectedDriver.nic_number}</p>
                                    <p><strong>License:</strong> {selectedDriver.license_number}</p>
                                    <p><strong>Address:</strong> {selectedDriver.home_address || 'N/A'}</p>
                                </div>
                                <div className="detail-section">
                                    <h4>Vehicle</h4>
                                    <p><strong>Type:</strong> {selectedDriver.vehicle_type}</p>
                                    <p><strong>Number:</strong> {selectedDriver.vehicle_number}</p>
                                </div>
                                <div className="detail-section">
                                    <h4>Bank Details</h4>
                                    <p><strong>Bank:</strong> {selectedDriver.bank_name}</p>
                                    <p><strong>Branch:</strong> {selectedDriver.branch_name}</p>
                                    <p><strong>Account Info:</strong> {selectedDriver.account_number} ({selectedDriver.account_holder_name})</p>
                                </div>
                            </div>

                            <div className="documents-section">
                                <h4>Verification Documents</h4>
                                <div className="docs-grid">
                                    <DocumentCard title="License Front" url={selectedDriver.license_front_image_url} />
                                    <DocumentCard title="License Back" url={selectedDriver.license_back_image_url} />
                                    <DocumentCard title="NIC Front" url={selectedDriver.nic_front_image_url} />
                                    <DocumentCard title="NIC Back" url={selectedDriver.nic_back_image_url} />
                                    <DocumentCard title="Vehicle Front" url={selectedDriver.vehicle_front_image_url} />
                                    <DocumentCard title="Vehicle Back" url={selectedDriver.vehicle_back_image_url} />
                                    <DocumentCard title="Vehicle Book" url={selectedDriver.vehicle_book_image_url} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

const DocumentCard = ({ title, url }) => (
    <div className="doc-card">
        <p>{title}</p>
        {url ? (
            <a href={url} target="_blank" rel="noopener noreferrer">
                <img src={url} alt={title} className="doc-preview" />
            </a>
        ) : (
            <div className="doc-missing">Missing</div>
        )}
    </div>
);

export default Drivers;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { User, Lock, Save, Store, Clock, Phone, Mail, MapPin } from 'lucide-react';
import './Settings.css';
import { API_URL } from './config';

const Settings = ({ currentUser }) => {
    const [activeTab, setActiveTab] = useState('profile');
    const [loading, setLoading] = useState(false);

    // Profile State
    const [profile, setProfile] = useState({
        name: currentUser.name || '',
        email: currentUser.email || '',
        phone: currentUser.phone || ''
    });

    // Laundry State (Only for Laundry Admin)
    const [laundry, setLaundry] = useState({
        name: '',
        address: '',
        phone: '',
        email: '',
        opening_time: '',
        closing_time: ''
    });

     
    useEffect(() => {
        if (currentUser.laundry_id && activeTab === 'laundry') {
            fetchLaundryDetails();
        }
    }, [activeTab, currentUser]);

    const fetchLaundryDetails = async () => {
        try {
            setLoading(true);
            const res = await axios.get(`${API_URL}/laundries/${currentUser.laundry_id}`);
            setLaundry(res.data);
        } catch (error) {
            console.error('Error fetching laundry:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleProfileUpdate = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            // Updated user profile endpoint needed or reuse existing
            // Since we don't have a direct "update my profile" endpoint easily exposed for admins in previous context,
            // we assumed /user/profile works for logged in user.
            // However, the previous userController.js used query param userId. 
            // We should use that.

            // Wait, admin login might not populate ID same way as user. 
            // Let's assume we can pass userId.
            // If it's a laundry admin, they are in 'laundries' table? 
            // If 'is_direct_branch' is true, they are a laundry, not a user in 'users' table.
            // Check Login.jsx: 
            // if (laundryRes.rows.length > 0) -> user.id = `l-${laundry.id}`.

            if (currentUser.is_direct_branch) {
                // It's a laundry account, so "Profile" is actually Laundry Basic Info?
                // Or maybe we just disable Profile tab for direct laundry accounts and force Laundry Settings.
                alert("Please use 'Laundry Settings' to update your branch information.");
                return;
            }

            await axios.put(`${API_URL}/user/profile?userId=${currentUser.id}`, profile);
            alert('Profile updated successfully!');
        } catch (error) {
            console.error('Update error:', error);
            alert('Failed to update profile.');
        } finally {
            setLoading(false);
        }
    };

    const handleLaundryUpdate = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await axios.put(`${API_URL}/laundries/${currentUser.laundry_id}`, laundry);
            alert('Laundry settings updated successfully!');
        } catch (error) {
            console.error('Update error:', error);
            alert('Failed to update laundry settings.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="settings-container">
            <div className="settings-header">
                <h2>Settings</h2>
                <div className="tabs">
                    {!currentUser.is_direct_branch && (
                        <button
                            className={`tab-btn ${activeTab === 'profile' ? 'active' : ''}`}
                            onClick={() => setActiveTab('profile')}
                        >
                            <User size={18} /> My Profile
                        </button>
                    )}
                    {(currentUser.role === 'admin' && currentUser.laundry_id) && (
                        <button
                            className={`tab-btn ${activeTab === 'laundry' ? 'active' : ''}`}
                            onClick={() => setActiveTab('laundry')}
                        >
                            <Store size={18} /> Laundry Settings
                        </button>
                    )}
                </div>
            </div>

            <div className="settings-content">
                {activeTab === 'profile' && !currentUser.is_direct_branch && (
                    <div className="card settings-card">
                        <h3>Personal Information</h3>
                        <form onSubmit={handleProfileUpdate}>
                            <div className="form-group">
                                <label>Full Name</label>
                                <div className="input-with-icon">
                                    <User size={18} />
                                    <input
                                        type="text"
                                        value={profile.name}
                                        onChange={(e) => setProfile({ ...profile, name: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div className="form-group">
                                <label>Email Address</label>
                                <div className="input-with-icon">
                                    <Mail size={18} />
                                    <input
                                        type="email"
                                        value={profile.email}
                                        onChange={(e) => setProfile({ ...profile, email: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div className="form-group">
                                <label>Phone Number</label>
                                <div className="input-with-icon">
                                    <Phone size={18} />
                                    <input
                                        type="tel"
                                        value={profile.phone}
                                        onChange={(e) => setProfile({ ...profile, phone: e.target.value })}
                                    />
                                </div>
                            </div>
                            <button type="submit" className="save-btn" disabled={loading}>
                                <Save size={18} /> {loading ? 'Saving...' : 'Save Changes'}
                            </button>
                        </form>
                    </div>
                )}

                {activeTab === 'laundry' && (
                    <div className="card settings-card">
                        <h3>Laundry Branch Details</h3>
                        <form onSubmit={handleLaundryUpdate}>
                            <div className="form-group">
                                <label>Branch Name</label>
                                <div className="input-with-icon">
                                    <Store size={18} />
                                    <input
                                        type="text"
                                        value={laundry.name}
                                        onChange={(e) => setLaundry({ ...laundry, name: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div className="form-group">
                                <label>Address</label>
                                <div className="input-with-icon">
                                    <MapPin size={18} />
                                    <input
                                        type="text"
                                        value={laundry.address}
                                        onChange={(e) => setLaundry({ ...laundry, address: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div className="row">
                                <div className="form-group col">
                                    <label>Opening Time</label>
                                    <div className="input-with-icon">
                                        <Clock size={18} />
                                        <input
                                            type="text"
                                            value={laundry.opening_time}
                                            onChange={(e) => setLaundry({ ...laundry, opening_time: e.target.value })}
                                        />
                                    </div>
                                </div>
                                <div className="form-group col">
                                    <label>Closing Time</label>
                                    <div className="input-with-icon">
                                        <Clock size={18} />
                                        <input
                                            type="text"
                                            value={laundry.closing_time}
                                            onChange={(e) => setLaundry({ ...laundry, closing_time: e.target.value })}
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="row">
                                <div className="form-group col">
                                    <label>Contact Email</label>
                                    <div className="input-with-icon">
                                        <Mail size={18} />
                                        <input
                                            type="email"
                                            value={laundry.email}
                                            onChange={(e) => setLaundry({ ...laundry, email: e.target.value })}
                                        />
                                    </div>
                                </div>
                                <div className="form-group col">
                                    <label>Contact Phone</label>
                                    <div className="input-with-icon">
                                        <Phone size={18} />
                                        <input
                                            type="tel"
                                            value={laundry.phone}
                                            onChange={(e) => setLaundry({ ...laundry, phone: e.target.value })}
                                        />
                                    </div>
                                </div>
                            </div>
                            <button type="submit" className="save-btn" disabled={loading}>
                                <Save size={18} /> {loading ? 'Saving...' : 'Update Laundry Details'}
                            </button>
                        </form>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Settings;
